676→            (PathBuf::from("pkg/handler.go"), Language::Go),
677→        ];
678→
679→        let registry = batch_analyze(&mut frontends, &files, None, None)
680→            .await
681→            .expect("batch analyze failed");
682→
683→        assert_eq!(registry.len(), 2);
684→        assert_eq!(
685→            registry.functions_in_file(Path::new("src/app.ts")).len(),
686→            1
687→        );
688→        assert_eq!(
